using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // ──────────────────────────────────────────────
    // CalculateTotal — DataRow (inline test values)
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 4, 0.08, 110.16, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.05, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "100% tax")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativeUnitPrice_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below zero")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // ──────────────────────────────────────────────
    // ApplyDiscount — DynamicData with ValueTuples
    // ──────────────────────────────────────────────

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (99.99m, 50m, 49.995m),
        (0m, 15m, 0m),
    ];

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal invalidPercent)> InvalidDiscountData =>
    [
        (100m, -1m),
        (100m, 101m),
        (100m, -0.01m),
        (100m, 100.01m),
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountData))]
    public void ApplyDiscount_InvalidDiscountPercent_ThrowsArgumentOutOfRange(
        decimal price, decimal invalidPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, invalidPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    // ──────────────────────────────────────────────
    // FormatPrice — DataRow for string assertions
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(9.99, "$", "$9.99", DisplayName = "Default currency")]
    [DataRow(1234.50, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(7.1, "£", "£7.10", DisplayName = "Pads to two decimals")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_DefaultCurrency_StartsWithDollarSign()
    {
        var result = _calculator.FormatPrice(42.00m);

        Assert.StartsWith("$", result);
    }
}

